challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The UPF is the source of a temporary media plane failure, causing an outage on the N3 data plane that resulted in dropped RTP packets.",
      "primary_suspect_nf": "upf",
      "probes": [
        {
          "tool": "get_network_status",
          "args_hint": "Check if the UPF container is running.",
          "expected_if_hypothesis_holds": "The UPF container is running, as the hypothesis suggests a temporary/transient fault, not a crash.",
          "falsifying_observation": "The UPF container is not in a running state, which would indicate a container-level crash rather than a transient media plane fault.",
          "conflates_with": []
        },
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "Get data-plane quality metrics for the UPF for a window around the anomaly time.",
          "expected_if_hypothesis_holds": "A sharp drop in packet rates and throughput for GTP-U traffic traversing the UPF, corroborating the 'activity_during_calls_collapsed' event.",
          "falsifying_observation": "The UPF's data plane metrics remain stable and show no significant drop in traffic, suggesting it was correctly forwarding all traffic it received.",
          "conflates_with": []
        },
        {
          "tool": "get_network_status",
          "args_hint": "Check the status of the SMF container.",
          "expected_if_hypothesis_holds": "The SMF container is running. A failure in the UPF's media plane should not be caused by the SMF.",
          "falsifying_observation": "The SMF container is not in a running state. This would suggest a control plane issue originating from the SMF might be the root cause.",
          "conflates_with": []
        }
      ],
      "notes": "This plan tests the integrity of the UPF, the primary suspect for the core data plane failure. It checks for container crashes versus transient faults and looks for direct evidence of a data plane traffic drop."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "RTPEngine is the source of the media plane degradation, experiencing a fault that is causing it to drop packets.",
      "primary_suspect_nf": "rtpengine",
      "probes": [
        {
          "tool": "measure_rtt",
          "args_hint": "Measure RTT and packet loss from the UPF to the RTPEngine.",
          "expected_if_hypothesis_holds": "High RTT or packet loss is observed on the path.",
          "falsifying_observation": "The probe's reading is inconsistent with rtpengine being the source (e.g. the metric stays at its healthy baseline, or the loss is observed on a path that does not traverse rtpengine).",
          "conflates_with": [
            "A fault in the UPF could cause similar symptoms.",
            "A fault in the underlying network path between the UPF and RTPEngine could cause similar symptoms."
          ]
        },
        {
          "tool": "measure_rtt",
          "args_hint": "Measure RTT and packet loss from the UPF to the P-CSCF as a partner probe.",
          "expected_if_hypothesis_holds": "The RTT and packet loss reading is normal, indicating the path from the UPF is generally healthy and the issue is specific to the path terminating at RTPEngine.",
          "falsifying_observation": "High RTT or packet loss is also observed on this path. This suggests the problem is more likely with the UPF or the shared network infrastructure, not isolated to RTPEngine.",
          "conflates_with": []
        },
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "Get data-plane quality metrics for RTPEngine for a window around the anomaly time.",
          "expected_if_hypothesis_holds": "RTPEngine's metrics show a high rate of discarded packets or a significant drop in media quality (e.g., MOS score).",
          "falsifying_observation": "RTPEngine's metrics show no anomalous behavior, indicating it was processing media streams correctly.",
          "conflates_with": []
        }
      ],
      "notes": "This plan addresses the linter feedback by using a compositional probe with a partner to isolate RTPEngine from the UPF and the network path. It also avoids mechanism-scoping language in the expected/falsifying observations."
    }
  ]
}

